     1→/**
     2→ * MMS Date/Time Utilities
     3→ *
     4→ * Timezone-aware date utilities for PM scheduling and compliance windows.
     5→ * All operations use Asia/Hong_Kong timezone as the default depot timezone.
     6→ *
     7→ * @see specs/004-backend-specification.md Section 4.4
     8→ */
     9→
    10→import {
    11→  addDays,
    12→  addMonths,
    13→  addWeeks,
    14→  differenceInDays,
    15→  endOfDay,
    16→  endOfWeek,
    17→  format,
    18→  isAfter,
    19→  isBefore,
    20→  isValid,
    21→  isWithinInterval,
    22→  parseISO,
    23→  startOfDay,
    24→  startOfWeek,
    25→} from 'date-fns';
    26→import { formatInTimeZone, toZonedTime, fromZonedTime } from 'date-fns-tz';
    27→
    28→/** Default timezone for MMS operations */
    29→export const DEFAULT_TIMEZONE = 'Asia/Hong_Kong';
    30→
    31→/** PM compliance window tolerance (±10%) */
    32→export const COMPLIANCE_TOLERANCE_PCT = 0.10;
    33→
    34→/** Day type for service demand */
    35→export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
    36→
    37→// =============================================================================
    38→// Timezone Utilities
    39→// =============================================================================
    40→
    41→/**
    42→ * Convert UTC date to local timezone
    43→ */
    44→export function toLocalTime(date: Date, timezone: string = DEFAULT_TIMEZONE): Date {
    45→  return toZonedTime(date, timezone);
    46→}
    47→
    48→/**
    49→ * Convert local timezone to UTC
    50→ */
    51→export function toUtc(date: Date, timezone: string = DEFAULT_TIMEZONE): Date {
    52→  return fromZonedTime(date, timezone);
    53→}
    54→
    55→/**
    56→ * Format date in specific timezone
