   256→
   257→/**
   258→ * Circuit breaker states
   259→ */
   260→export type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';
   261→
   262→/**
   263→ * Circuit breaker configuration
   264→ */
   265→export interface CircuitBreakerConfig {
